import os
import sys
import shutil
import subprocess
import tempfile
import zipfile
from pathlib import Path


def run(cmd, cwd=None, env=None):
    print("+", " ".join(cmd), flush=True)
    subprocess.run(cmd, cwd=cwd, env=env, check=True)


def getenv_bool(name, default=False):
    v = os.getenv(name)
    if v is None:
        return default
    return v.strip().lower() in ("1", "true", "yes", "y", "on")


def detect_repo_root():
    start = Path.cwd()
    for p in [start, *start.parents]:
        if (p / "requirements.txt").exists() or (p / ".git").exists() or (p / "pyproject.toml").exists():
            return p
    return start


def ensure_venv(venv_dir: Path):
    py = sys.executable
    if not venv_dir.exists():
        run([py, "-m", "venv", str(venv_dir)])
    if os.name == "nt":
        vpy = venv_dir / "Scripts" / "python.exe"
    else:
        vpy = venv_dir / "bin" / "python"
    if not vpy.exists():
        raise RuntimeError(f"Virtualenv python not found at {vpy}")
    return vpy


def pip_install(python_exe: Path, repo_root: Path, requirements: Path):
    run([str(python_exe), "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel"], cwd=repo_root)
    run([str(python_exe), "-m", "pip", "install", "-r", str(requirements)], cwd=repo_root)


def run_tests(python_exe: Path, repo_root: Path):
    test_cmd = os.getenv("TEST_CMD", "").strip()
    if test_cmd:
        run([str(python_exe), "-m", *test_cmd.split()], cwd=repo_root)
        return

    # Prefer pytest if available, otherwise unittest discovery
    try:
        run([str(python_exe), "-m", "pytest", "-q"], cwd=repo_root)
    except subprocess.CalledProcessError:
        run([str(python_exe), "-m", "unittest", "discover", "-q"], cwd=repo_root)


def should_exclude(rel_posix: str):
    parts = rel_posix.split("/")
    if any(p in (".git", ".hg", ".svn", "__pycache__", ".pytest_cache", ".mypy_cache", ".ruff_cache", ".tox", ".venv", "venv") for p in parts):
        return True
    if parts and parts[0] in ("dist", "build"):
        return True
    if rel_posix.endswith((".pyc", ".pyo")):
        return True
    return False


def safe_copytree(src: Path, dst: Path):
    for root, dirs, files in os.walk(src):
        r = Path(root)
        rel = r.relative_to(src).as_posix()
        if rel == ".":
            rel = ""
        if rel and should_exclude(rel):
            dirs[:] = []
            continue
        # prune excluded dirs
        pruned = []
        for d in dirs:
            drel = (Path(rel) / d).as_posix() if rel else d
            if should_exclude(drel):
                pruned.append(d)
        for d in pruned:
            dirs.remove(d)

        out_dir = dst / rel if rel else dst
        out_dir.mkdir(parents=True, exist_ok=True)

        for f in files:
            frel = (Path(rel) / f).as_posix() if rel else f
            if should_exclude(frel):
                continue
            s = r / f
            t = out_dir / f
            t.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(s, t)


def build_wheel_if_possible(python_exe: Path, repo_root: Path, out_dir: Path):
    pyproject = repo_root / "pyproject.toml"
    setup_py = repo_root / "setup.py"
    setup_cfg = repo_root / "setup.cfg"
    if not (pyproject.exists() or setup_py.exists() or setup_cfg.exists()):
        return None

    out_dir.mkdir(parents=True, exist_ok=True)

    cmd = os.getenv("BUILD_CMD", "").strip()
    if cmd:
        run([str(python_exe), "-m", *cmd.split(), str(out_dir)], cwd=repo_root)
    else:
        try:
            run([str(python_exe), "-m", "build", "--wheel", "--outdir", str(out_dir)], cwd=repo_root)
        except subprocess.CalledProcessError:
            run([str(python_exe), "-m", "pip", "install", "--upgrade", "build"], cwd=repo_root)
            run([str(python_exe), "-m", "build", "--wheel", "--outdir", str(out_dir)], cwd=repo_root)

    wheels = sorted(out_dir.glob("*.whl"), key=lambda p: p.stat().st_mtime, reverse=True)
    return wheels[0] if wheels else None


def create_source_zip(repo_root: Path, artifact_path: Path, include_venv=False, venv_dir: Path | None = None):
    staging = Path(tempfile.mkdtemp(prefix="package_staging_"))
    try:
        safe_copytree(repo_root, staging / "app")

        if include_venv and venv_dir is not None and venv_dir.exists():
            safe_copytree(venv_dir, staging / "venv")

        artifact_path.parent.mkdir(parents=True, exist_ok=True)
        if artifact_path.exists():
            artifact_path.unlink()

        with zipfile.ZipFile(artifact_path, "w", compression=zipfile.ZIP_DEFLATED, compresslevel=6) as zf:
            for root, _, files in os.walk(staging):
                r = Path(root)
                for f in files:
                    p = r / f
                    arc = p.relative_to(staging).as_posix()
                    zf.write(p, arcname=arc)
    finally:
        shutil.rmtree(staging, ignore_errors=True)


def main():
    repo_root = Path(os.getenv("REPO_ROOT", "")).expanduser()
    if not repo_root.as_posix():
        repo_root = detect_repo_root()
    repo_root = repo_root.resolve()

    requirements = repo_root / os.getenv("REQUIREMENTS_FILE", "requirements.txt")
    if not requirements.exists():
        raise SystemExit(f"requirements file not found: {requirements}")

    venv_dir = (repo_root / os.getenv("VENV_DIR", ".venv")).resolve()
    artifact_dir = (repo_root / os.getenv("ARTIFACT_DIR", "dist")).resolve()
    artifact_name = os.getenv("ARTIFACT_NAME", "deployment_package.zip").strip() or "deployment_package.zip"
    artifact_path = artifact_dir / artifact_name

    skip_tests = getenv_bool("SKIP_TESTS", False)
    include_venv = getenv_bool("INCLUDE_VENV", False)
    build_wheel = getenv_bool("BUILD_WHEEL", True)

    python_exe = ensure_venv(venv_dir)
    pip_install(python_exe, repo_root, requirements)

    if not skip_tests:
        run_tests(python_exe, repo_root)

    if build_wheel:
        wheel_out = artifact_dir / "wheel"
        build_wheel_if_possible(python_exe, repo_root, wheel_out)

    create_source_zip(repo_root, artifact_path, include_venv=include_venv, venv_dir=venv_dir)

    print(f"Artifact created: {artifact_path}")


if __name__ == "__main__":
    main()